"use client";
import { useState, useRef, useEffect } from 'react';
import Link from 'next/link';
import { 
  Send, Sparkles, User, BrainCircuit, Cpu, 
  HelpCircle, History, MessageSquare, ArrowRight, Loader2, Link2 
} from 'lucide-react';

interface ChatMessage {
  role: 'user' | 'assistant';
  text: string;
  isStreaming?: boolean;
  citations?: {
    id: string;
    type: 'deployment' | 'incident';
    name: string;
    detail: string;
  }[];
}

const SUGGESTED_PROMPTS = [
  "What went wrong the last time auth-service was deployed?",
  "Show me incidents linked to database migrations.",
  "Which services have the highest failure rates on Fridays?"
];

export default function ChatPage() {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { 
      role: 'assistant', 
      text: 'Hello! I am the PipelineIQ DevOps Intelligence Agent. I query Hindsight episodic memory to pull insights on deployment risk patterns, active outages, and historical resolutions. Ask me a question about your pipelines.' 
    }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [chatHistory, setChatHistory] = useState([
    { id: 1, title: 'auth-service deployment outage', date: 'Just now' },
    { id: 2, title: 'stripe API migration risks', date: '2h ago' },
    { id: 3, title: 'weekly incident frequency audit', date: 'Yesterday' }
  ]);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = (textToSend: string) => {
    if (!textToSend.trim()) return;

    // Add user message
    const userMsg: ChatMessage = { role: 'user', text: textToSend };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsTyping(true);

    // Simulate AI response logic
    setTimeout(() => {
      setIsTyping(false);
      
      let replyText = "";
      let citations: ChatMessage['citations'] = [];

      const normalizedText = textToSend.toLowerCase();

      if (normalizedText.includes('auth-service') || normalizedText.includes('wrong')) {
        replyText = "The last deployment of auth-service (v2.4.1) occurred 4 hours ago by @arjun in Staging. A database schema alteration was included for JWT token table rotations. Hindsight memory matched this change at 94% similarity to v2.3.8 (Dec 12, 2025) which caused an 8-minute production database locking spike. I recommend blocking the promotion of v2.4.1 to Production until you verify table lock times.";
        citations = [
          { id: 'dep-101', type: 'deployment', name: 'auth-service v2.4.1', detail: 'Staging • 67 Risk score' }
        ];
      } else if (normalizedText.includes('incident') || normalizedText.includes('migration')) {
        replyText = "I pulled 2 incidents associated with database alterations in the last 24 hours: \n\n1. P1 Latency Spike on payment-service: Triggered post Stripe SDK v1.8.2 deployment (Yesterday). Resolution is ongoing. Hindsight recalled a past Stripe migration in v1.8.1 with similar signatures.\n2. P2 Webpack compile failure on auth-service: Started 5 hours ago, associated with middleware JWT schemas integrations.";
        citations = [
          { id: 'dep-103', type: 'deployment', name: 'payment-service v1.8.2', detail: 'Stripe API Migration' },
          { id: 'dep-101', type: 'deployment', name: 'auth-service v2.4.1', detail: 'JWT Schema Refactor' }
        ];
      } else if (normalizedText.includes('friday') || normalizedText.includes('rate')) {
        replyText = "payment-service has the highest Friday failure rate (88.3% regression probability). SRE analysis shows Friday deployments of Stripe API clients consistently collide with high transaction rate peaks, resulting in DB deadlock spikes. SRE recommendations advise a strict freeze on payment service upgrades after Thursday 12:00 PM.";
        citations = [
          { id: 'dep-103', type: 'deployment', name: 'payment-service v1.8.2', detail: '89 Risk Score' }
        ];
      } else {
        replyText = "I queried the active deployment cluster and memory cache blocks. The overall system shows 12 out of 14 healthy services. However, payment-service currently has an active P1 Latency Spike incident linked to deployment v1.8.2 (Stripe SDK update). Let me know if you would like me to retrieve the post-mortem steps or rollback instructions for Stripe integrations.";
        citations = [
          { id: 'dep-103', type: 'deployment', name: 'payment-service v1.8.2', detail: 'Stripe SDK update • 89 Risk' }
        ];
      }

      // Stream the response word by word
      const words = replyText.split(' ');
      let currentWordIndex = 0;
      
      const newResponseMsg: ChatMessage = {
        role: 'assistant',
        text: '',
        isStreaming: true,
        citations
      };

      setMessages(prev => [...prev, newResponseMsg]);

      const interval = setInterval(() => {
        if (currentWordIndex < words.length) {
          const partialText = words.slice(0, currentWordIndex + 1).join(' ');
          setMessages(prev => {
            const copy = [...prev];
            const last = copy[copy.length - 1];
            if (last && last.role === 'assistant') {
              last.text = partialText;
            }
            return copy;
          });
          currentWordIndex++;
        } else {
          clearInterval(interval);
          setMessages(prev => {
            const copy = [...prev];
            const last = copy[copy.length - 1];
            if (last && last.role === 'assistant') {
              last.isStreaming = false;
            }
            return copy;
          });
        }
      }, 30);

    }, 1500);
  };

  return (
    <div className="h-[calc(100vh-64px)] flex border-l border-[#2A2F45]/50 overflow-hidden select-none">
      
      {/* Left Chat Sidebar: History */}
      <aside className="w-64 bg-[#13161E]/40 border-r border-[#2A2F45]/50 flex flex-col h-full shrink-0 hidden md:flex">
        <div className="p-4 border-b border-[#2A2F45]/50 flex items-center gap-2">
          <History size={14} className="text-[#8B91B5]" />
          <span className="text-xs font-bold text-[#F0F2FF] uppercase tracking-wider">Conversation History</span>
        </div>
        
        <div className="flex-1 p-3.5 space-y-2 overflow-y-auto">
          {chatHistory.map(hist => (
            <button 
              key={hist.id} 
              className="w-full text-left p-2.5 rounded-lg text-xs text-[#8B91B5] hover:text-[#F0F2FF] hover:bg-[#1C2030]/50 border border-transparent hover:border-[#2A2F45]/50 transition-all flex flex-col gap-1 group"
            >
              <span className="font-semibold truncate group-hover:text-[#4F7FFF] transition-colors">{hist.title}</span>
              <span className="text-[9px] text-[#4A5070]">{hist.date}</span>
            </button>
          ))}
        </div>
      </aside>

      {/* Main Chat Area */}
      <div className="flex-1 flex flex-col h-full bg-[#0D0F14] relative">
        <div className="absolute top-0 inset-x-0 h-14 bg-gradient-to-b from-[#0D0F14] to-transparent pointer-events-none z-10" />
        
        {/* Messages list */}
        <div className="flex-1 overflow-y-auto p-6 md:p-8 space-y-6 pt-10 pb-28">
          {messages.map((m, idx) => {
            const isAI = m.role === 'assistant';
            return (
              <div 
                key={idx} 
                className={`flex gap-4 max-w-4xl mx-auto ${isAI ? 'animate-fade-in' : 'flex-row-reverse'}`}
              >
                {/* Avatar */}
                <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 shadow-md ${
                  isAI 
                    ? 'bg-gradient-to-br from-[#4F7FFF] to-[#A78BFA] text-[#0D0F14]' 
                    : 'bg-[#1C2030] text-[#4F7FFF] border border-[#2A2F45]'
                }`}>
                  {isAI ? <BrainCircuit size={16} className="stroke-[2.5]" /> : <User size={15} />}
                </div>

                {/* Bubble */}
                <div className="space-y-3 max-w-[80%]">
                  <div className={`p-4 rounded-xl text-xs leading-relaxed border ${
                    isAI 
                      ? 'bg-[#13161E] border-[#2A2F45] text-[#F0F2FF] rounded-tl-none shadow-md' 
                      : 'bg-gradient-to-br from-[#4F7FFF]/15 to-[#4F7FFF]/5 border-[#4F7FFF]/20 text-[#F0F2FF] rounded-tr-none shadow-sm'
                  }`}>
                    <p className="whitespace-pre-line">{m.text}</p>
                  </div>

                  {/* Render citations if available */}
                  {isAI && m.citations && m.citations.length > 0 && !m.isStreaming && (
                    <div className="flex flex-wrap gap-2.5 pt-1">
                      {m.citations.map((cit) => (
                        <Link 
                          key={cit.id}
                          href={`/deployments/${cit.id}`}
                          className="inline-flex items-center gap-1.5 px-3 py-1 bg-[#A78BFA]/5 border border-[#A78BFA]/15 rounded-lg text-[10px] text-[#A78BFA] hover:bg-[#A78BFA]/10 hover:border-[#A78BFA]/30 transition-all font-mono font-bold"
                        >
                          <Link2 size={10} />
                          <span>{cit.name}</span>
                          <span className="text-[#8B91B5] font-normal font-sans">({cit.detail})</span>
                        </Link>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            );
          })}

          {/* Typing loader */}
          {isTyping && (
            <div className="flex gap-4 max-w-4xl mx-auto">
              <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-[#4F7FFF] to-[#A78BFA] text-[#0D0F14] flex items-center justify-center shrink-0 shadow-md">
                <BrainCircuit size={16} className="stroke-[2.5] animate-spin" />
              </div>
              <div className="bg-[#13161E] border border-[#2A2F45] p-3 rounded-xl rounded-tl-none flex items-center justify-center">
                <Loader2 size={14} className="text-[#A78BFA] animate-spin" />
                <span className="text-[10px] text-[#8B91B5] ml-2 font-medium">Hindsight is recalling memories...</span>
              </div>
            </div>
          )}

          <div ref={messagesEndRef} />
        </div>

        {/* Input Dock and suggested prompts */}
        <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-[#0D0F14] via-[#0D0F14]/90 to-transparent p-6 pt-10">
          <div className="max-w-4xl mx-auto space-y-4">
            
            {/* Show suggested prompts only on load (first assistant message only) */}
            {messages.length === 1 && !isTyping && (
              <div className="flex flex-wrap gap-2.5 justify-center md:justify-start">
                {SUGGESTED_PROMPTS.map((prompt) => (
                  <button
                    key={prompt}
                    onClick={() => handleSend(prompt)}
                    className="text-[10px] font-semibold text-[#8B91B5] bg-[#13161E] hover:bg-[#1C2030] hover:text-[#F0F2FF] border border-[#2A2F45] rounded-lg px-3 py-1.5 transition-colors text-left"
                  >
                    {prompt}
                  </button>
                ))}
              </div>
            )}

            {/* Input Bar */}
            <div className="relative flex items-center">
              <input
                type="text"
                value={inputValue}
                onChange={(e) => setInputValue(e.target.value)}
                onKeyDown={(e) => { if (e.key === 'Enter') handleSend(inputValue); }}
                placeholder="Ask about pipeline failures, risk factors, patterns..."
                className="w-full bg-[#13161E] border border-[#2A2F45] rounded-xl py-3.5 pl-5 pr-14 text-xs text-[#F0F2FF] placeholder-[#4A5070] focus:outline-none focus:border-[#4F7FFF] focus:ring-1 focus:ring-[#4F7FFF] transition-all shadow-xl"
              />
              <button
                onClick={() => handleSend(inputValue)}
                className="absolute right-2.5 p-2 bg-[#4F7FFF] hover:bg-[#4F7FFF]/90 text-white rounded-lg transition-all shadow-md shadow-[#4F7FFF]/10"
              >
                <Send size={14} />
              </button>
            </div>
          </div>
        </div>

      </div>

    </div>
  );
}